from math import gcd
class Solution:
    def subarrayGCD(self, nums, k):
        n = len(nums)
        count = 0
        for i in range(n):
            g = 0
            for j in range(i, n):
                g = gcd(g, nums[j])
                if g == k:
                    count += 1
                elif g % k != 0:
                    break
        return count

