var subarrayGCD = function(nums, k) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    let ans = 0;
    for (let i = 0; i < nums.length; i++) {
        let g = 0;
        for (let j = i; j < nums.length; j++) {
            g = gcd(g, nums[j]);
            if (g % k !== 0) break;
            if (g === k) ans++;
        }
    }
    return ans;
};
